INSERT INTO questions (title, content, answer, difficulty, category_id, source_type, source_url, source_name, review_status, published_at) SELECT 'React 中 useEffect 和 useLayoutEffect 的区别是什么？', '请说明两者的执行时机，以及分别适合处理什么问题。', 'useEffect 在浏览器完成绘制后执行，适合副作用与异步逻辑；useLayoutEffect 在 DOM 变更后、浏览器绘制前同步执行，适合读取布局和避免闪烁。', 'medium', c.id, 'imported', NULL, 'manual', 1, NOW() FROM categories c WHERE c.slug = 'react';
