INSERT INTO questions (title, content, answer, difficulty, category_id, source_type, source_url, source_name, review_status, published_at) SELECT 'TypeScript 中 unknown 和 any 的区别是什么？', '请从类型安全、使用限制和推荐场景说明区别。', 'any 会跳过类型检查，任何操作都能通过；unknown 更安全，使用前必须先缩小类型或断言，因此更适合不确定的外部输入。', 'easy', c.id, 'imported', NULL, 'manual', 1, NOW() FROM categories c WHERE c.slug = 'typescript';
